// Generic callback type
type Callback<T> = (error: Error | null, result?: T) => void;

function asyncOperation<T>(value: T, cb: Callback<T>): void {
  setTimeout(() => {
    cb(null, value);
  }, 100);
}

asyncOperation<string>("hello", (err, result) => {
  if (err) {
    console.error(err);
    return;
  }
  console.log(result?.toUpperCase());
});

